/**
 * decode-quality-reporter.test.ts — the pure grading + dip/up logic.
 *
 * Covers MESH_QUALITY_REPORTING_FRAMEWORK.md §1–§2b:
 *   - grade bands (AAA≥20, AA≥15, A≥10, B≥5, C≥1, D∈(0,1), F=0) loaded from
 *     mesh-decode-budget.json,
 *   - correctness gate (divergent ⇒ F),
 *   - establish warm grade, then grade_dip / grade_up transitions across floors,
 *   - dip names a cause component.
 * No OTel/IO here — the emitter is a separate, side-effecting module.
 */

import { describe, expect, it } from 'vitest';
import {
  DecodeQualityReporter,
  gradeForTps,
  gradeFloorTps,
  gradeOrdinal,
  isBetterGrade,
  componentBytesGb,
  type DecodeGrade,
} from './decode-quality-reporter';

// A reporter that feeds `n` tokens each at the ms/token for a target tok/s.
// Returns the LAST non-null snapshot the burst produced — i.e. the final grade
// crossing reached during the burst (the window may cross multiple bands as it
// fills, and each crossing emits once; the last one is the settled grade).
function feed(
  reporter: DecodeQualityReporter,
  tps: number,
  n: number,
  opts: Parameters<DecodeQualityReporter['record']>[1] = {},
) {
  const ms = tps > 0 ? 1000 / tps : 1_000_000;
  let lastEmit = null as ReturnType<DecodeQualityReporter['record']>;
  for (let i = 0; i < n; i++) {
    const snap = reporter.record(ms, opts);
    if (snap) lastEmit = snap;
  }
  return lastEmit;
}

describe('grade bands (from mesh-decode-budget.json)', () => {
  it('maps sustained tok/s to the highest band whose floor it clears', () => {
    expect(gradeForTps(25)).toBe('AAA'); // ≥20
    expect(gradeForTps(20)).toBe('AAA'); // boundary inclusive
    expect(gradeForTps(15)).toBe('AA'); // ≥15
    expect(gradeForTps(13.13)).toBe('A'); // the live grade
    expect(gradeForTps(10)).toBe('A'); // boundary
    expect(gradeForTps(7)).toBe('B'); // ≥5
    expect(gradeForTps(2)).toBe('C'); // ≥1
    expect(gradeForTps(0.5)).toBe('D'); // (0,1)
  });

  it('grades 0 tok/s and non-finite as F (no real measurement ⇒ broken)', () => {
    expect(gradeForTps(0)).toBe('F');
    expect(gradeForTps(-1)).toBe('F');
    expect(gradeForTps(Number.NaN)).toBe('F');
    // A non-finite rate is not a real sustained measurement → F, not AAA.
    expect(gradeForTps(Number.POSITIVE_INFINITY)).toBe('F');
  });

  it('correctness gates everything: any divergence ⇒ F regardless of speed', () => {
    expect(gradeForTps(30, 1)).toBe('F'); // would be AAA on speed alone
    expect(gradeForTps(30, 0)).toBe('AAA');
  });

  it('band floors come straight from the budget JSON', () => {
    expect(gradeFloorTps('AAA')).toBe(20);
    expect(gradeFloorTps('AA')).toBe(15);
    expect(gradeFloorTps('A')).toBe(10);
    expect(gradeFloorTps('B')).toBe(5);
    expect(gradeFloorTps('C')).toBe(1);
  });

  it('grade_ordinal is monotone AAA=6 … F=0', () => {
    const order: DecodeGrade[] = ['AAA', 'AA', 'A', 'B', 'C', 'D', 'F'];
    const ordinals = order.map(gradeOrdinal);
    expect(ordinals).toEqual([6, 5, 4, 3, 2, 1, 0]);
    for (let i = 1; i < ordinals.length; i++) {
      expect(ordinals[i]!).toBeLessThan(ordinals[i - 1]!);
    }
  });

  it('isBetterGrade orders by quality', () => {
    expect(isBetterGrade('AA', 'A')).toBe(true);
    expect(isBetterGrade('A', 'AA')).toBe(false);
    expect(isBetterGrade('A', 'F')).toBe(true);
    expect(isBetterGrade('A', 'A')).toBe(false);
  });

  it('exposes the per-component byte tables (q8 live lane)', () => {
    expect(componentBytesGb('ffn_matvec', 'q8')).toBeCloseTo(5.99);
    expect(componentBytesGb('qkv_matvec', 'f16')).toBeCloseTo(1.61);
    expect(componentBytesGb('logit_matvec', 'q4k')).toBeCloseTo(0.075);
  });
});

describe('rolling window → sustained tok/s + grade', () => {
  it('computes sustained tok/s as the windowed running mean', () => {
    const r = new DecodeQualityReporter({ windowSize: 4, establishAfterTokens: 4 });
    feed(r, 10, 4); // 100ms/token → 10 tok/s
    expect(r.sustainedTps).toBeCloseTo(10, 5);
    expect(r.grade).toBe('A');
  });

  it('the window forgets old tokens (a fast burst recovers the grade)', () => {
    const r = new DecodeQualityReporter({ windowSize: 4, establishAfterTokens: 4 });
    feed(r, 1, 4); // slow: 1 tok/s → C
    expect(r.grade).toBe('C');
    feed(r, 20, 4); // fill the window with fast tokens → AAA
    expect(r.sustainedTps).toBeGreaterThanOrEqual(20);
    expect(r.grade).toBe('AAA');
  });
});

describe('establish + dip/up transitions', () => {
  it('establishes the warm grade after one full window and emits once', () => {
    const r = new DecodeQualityReporter({ windowSize: 4, establishAfterTokens: 4 });
    expect(feed(r, 13, 3)).toBeNull(); // not yet established
    const snap = r.record(1000 / 13); // 4th token establishes
    expect(snap).not.toBeNull();
    expect(snap!.establishedGrade).toBe('A');
    expect(r.established).toBe('A');
    // No transition snapshot on a steady 5th token at the same grade.
    expect(r.record(1000 / 13)).toBeNull();
  });

  it('fires grade_dip with from/to when sustained tps drops below the floor', () => {
    const r = new DecodeQualityReporter({ windowSize: 4, establishAfterTokens: 4 });
    feed(r, 16, 4); // establish at AA (clear of the 15 floor)
    expect(r.established).toBe('AA');
    // Slow tokens drag the windowed mean under the 15 floor. Capture the FIRST
    // emitted transition so we read the AA → (lower) crossing, not a later one
    // (the window may cross multiple bands as it fills with slow tokens).
    let firstDip: ReturnType<DecodeQualityReporter['record']> = null;
    for (let i = 0; i < 4 && !firstDip; i++) firstDip = r.record(1000 / 5);
    expect(firstDip).not.toBeNull();
    expect(firstDip!.transition?.kind).toBe('grade_dip');
    expect(firstDip!.transition?.from).toBe('AA');
    expect(['A', 'B', 'C', 'D', 'F']).toContain(firstDip!.transition!.to);
    expect(isBetterGrade(firstDip!.transition!.from, firstDip!.transition!.to)).toBe(true);
  });

  it('fires grade_up when a kernel speedup crosses a band UP', () => {
    const r = new DecodeQualityReporter({ windowSize: 4, establishAfterTokens: 4 });
    feed(r, 10, 4); // establish at A
    expect(r.established).toBe('A');
    // Fast burst: the window crosses A→AA→AAA as it fills; the last crossing is
    // the settled grade_up reaching AAA.
    const up = feed(r, 30, 4);
    expect(up).not.toBeNull();
    expect(up!.transition?.kind).toBe('grade_up');
    expect(up!.transition?.to).toBe('AAA');
    expect(r.established).toBe('AAA');
    expect(isBetterGrade(up!.transition!.to, up!.transition!.from)).toBe(true);
  });

  it('re-establishes at the new grade so each crossing emits exactly once', () => {
    const r = new DecodeQualityReporter({ windowSize: 4, establishAfterTokens: 4 });
    feed(r, 10, 4); // A
    const up = feed(r, 30, 4); // window settles at AAA via one-per-crossing emits
    expect(up!.transition?.kind).toBe('grade_up');
    expect(r.established).toBe('AAA');
    // Steady at AAA now → no further emit (each crossing already reported once).
    expect(r.record(1000 / 30)).toBeNull();
    expect(r.record(1000 / 30)).toBeNull();
  });

  it('a divergent token forces F (correctness dip) even at full speed', () => {
    const r = new DecodeQualityReporter({ windowSize: 4, establishAfterTokens: 4 });
    feed(r, 20, 4); // establish AAA
    expect(r.established).toBe('AAA');
    const broke = r.record(1000 / 20, { divergent: true });
    expect(broke).not.toBeNull();
    expect(broke!.transition?.kind).toBe('grade_dip');
    expect(broke!.grade).toBe('F');
    expect(broke!.divergentTokens).toBe(1);
  });
});

describe('dip cause component', () => {
  it('names the component most over its byte budget as the dip cause', () => {
    const r = new DecodeQualityReporter({ windowSize: 4, establishAfterTokens: 4 });
    feed(r, 15, 4); // establish AA
    // FFN reads ~6GB/token; a 200ms FFN is far below budget GB/s vs a cheap
    // qkv at 5ms — but score is ms/byte, so make qkv the anomaly: tiny bytes,
    // big ms.
    const dip = feed(r, 5, 4, {
      componentMs: { qkv_matvec: 80, ffn_matvec: 60, o_matvec: 5, logit_matvec: 2 },
    });
    expect(dip!.transition?.kind).toBe('grade_dip');
    // qkv: 80ms / 0.86GB ≈ 93 ms/GB  vs  ffn: 60 / 5.99 ≈ 10 ms/GB → qkv worst.
    expect(dip!.transition?.causeComponent).toBe('qkv_matvec');
  });

  it('component samples carry achieved GB/s from the budget bytes', () => {
    const r = new DecodeQualityReporter({ windowSize: 2, establishAfterTokens: 2 });
    r.record(50, { componentMs: { ffn_matvec: 50 } });
    r.record(50, { componentMs: { ffn_matvec: 50 } });
    const samples = r.snapshot().components;
    const ffn = samples.find((s) => s.component === 'ffn_matvec');
    expect(ffn).toBeDefined();
    // 5.99 GB / 0.050 s ≈ 119.8 GB/s
    expect(ffn!.gbs).toBeCloseTo(5.99 / 0.05, 1);
  });
});

describe('snapshot shape (the OTel emit contract)', () => {
  it('carries model, tps, grade, ordinal, divergent, window', () => {
    const r = new DecodeQualityReporter({
      windowSize: 4,
      establishAfterTokens: 4,
      model: 'mistral-7b',
    });
    const snap = feed(r, 13, 4)!;
    expect(snap.model).toBe('mistral-7b');
    expect(snap.grade).toBe('A');
    expect(snap.gradeOrdinal).toBe(gradeOrdinal('A'));
    expect(snap.windowSize).toBe(4);
    expect(snap.divergentTokens).toBe(0);
    expect(snap.tps).toBeCloseTo(13, 5);
  });
});
